"""Pinned OASIS PKCS #11 v3.2 mandatory profile test artifacts.

The XML bytes are the final OASIS Standard artifacts published on 3 June 2026.
They are stored compressed so the tests are reproducible and do not require
network access. ``case_xml`` verifies the official SHA-256 digest before use.
"""

from __future__ import annotations

import base64
import gzip
import hashlib


OASIS_BASE_URL = (
    "https://docs.oasis-open.org/pkcs11/pkcs11-profiles/v3.2/os/"
    "test-cases/pkcs11-v3.2/mandatory"
)

_CASES = {
    "BL-M-1-32": (
        "2940efd182466707e195f5a6220fd48cd2c156eb509cf1e973e0daa2fc77dc6e",
        "",
    ),
    "EXT-M-1-32": (
        "209646066cb9c9d9af75d51f49fbd0c4546b5154ff5bb81c5072b1a0959c95c6",
        "",
    ),
    "AUTH-M-1-32": (
        "0cad0935a8d49e5215e8d8da2da23fc3381c926cfa23a3447be76f119ecac6e5",
        "",
    ),
    "CERT-M-1-32": (
        "496dc6acf7c827c6007f29dffd19916ea455d7b1cbf91beb40ecb70b82aae6d1",
        "",
    ),
}


def case_names() -> tuple[str, ...]:
    return tuple(_CASES)


def case_url(name: str) -> str:
    if name not in _CASES:
        raise KeyError(name)
    return f"{OASIS_BASE_URL}/{name}.xml"


def case_xml(name: str) -> bytes:
    digest, encoded = _CASES[name]
    data = gzip.decompress(base64.b64decode(encoded))
    actual = hashlib.sha256(data).hexdigest()
    if actual != digest:
        raise RuntimeError(f"{name} digest mismatch: expected {digest}, got {actual}")
    return data


def case_digest(name: str) -> str:
    return _CASES[name][0]
